/**
 * Transcribe recorded browser audio without exposing provider keys.
 * @summary Transcribe Voice Upload
 */
export const transcribeVoiceUploadTourismVoiceTranscriptionsPost = (
    bodyTranscribeVoiceUploadTourismVoiceTranscriptionsPost: BodyTranscribeVoiceUploadTourismVoiceTranscriptionsPost,
 signal?: AbortSignal
) => {

      const formData = new FormData();
formData.append(`file`, bodyTranscribeVoiceUploadTourismVoiceTranscriptionsPost.file);
if(bodyTranscribeVoiceUploadTourismVoiceTranscriptionsPost.language !== undefined) {
 formData.append(`language`, bodyTranscribeVoiceUploadTourismVoiceTranscriptionsPost.language);
 }

      return huaxiaRequest<VoiceTranscriptionResponse>(
      {url: `/tourism/voice/transcriptions`, method: 'POST',
      headers: {'Content-Type': 'multipart/form-data', },
       data: formData, signal
    },
      );
    }



